changeSet.sql:
CREATE TABLE control_categories
(
	id serial,
	control_function_id integer DEFAULT NULL,
	name character varying (255) NOT NULL DEFAULT '',
	description text DEFAULT NULL,
	CONSTRAINT pk_control_categories PRIMARY KEY (id)
	, CONSTRAINT fk_control_categories_to_control_function FOREIGN KEY (control_function_id) REFERENCES control_functions (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_control_categories_control_function ON control_categories (control_function_id);
CREATE INDEX i_control_categories_name ON control_categories (name);
